import java.io.*;

public class Main {
    public static void main(String[] args) {
        // FileReaderクラスのインスタンスを作成します。
        FileReader fr = null;
        try {
            fr = new FileReader("data.txt");
            // BufferedReaderクラスのインスタンスを作成します。
            BufferedReader br = new BufferedReader(fr);

            // ファイルから1行ずつ読み込み、標準出力に出力します。
            String line;
            while ((line = br.readLine()) != null) {
                // System.out.printlnを使用して、読み込んだ行を出力します。
                // このコードでは、data.txtの内容が標準出力に出力されます。
                System.out.println(line);
            }
        } catch (FileNotFoundException e) {
            // FileNotFoundExceptionが発生した場合、エラーメッセージを出力します。
            // このコードでは、data.txtが存在しない場合にこの例外が発生します。
            e.printStackTrace();
        } catch (IOException e) {
            // IOExceptionが発生した場合、エラーメッセージを出力します。
            e.printStackTrace();
        } finally {
            try {
                if (fr != null) {
                    fr.close();
                }
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Scannerクラスのインスタンスを作成します。
        // System.inは、標準入力（キーボードからの入力）を表します。
        Scanner scanner = new Scanner(System.in);

        // ユーザーに文字列の入力を促します。
        System.out.println("Please input a string:");

        // ScannerのnextLineメソッドを使用して、ユーザーが入力した文字列を取得します。
        String input = scanner.nextLine();

        // ユーザーが入力した文字列を出力します。
        // このコードでは、ユーザーが入力した文字列がそのまま標準出力に出力されます。
        System.out.println(input);

        // Scannerを閉じます。
        scanner.close();
    }
}

